  ('social-worker-moex-05170', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '優勢觀點的基本概念，下列何者錯誤？', '["協助人們因夥伴關係而有歸屬感", "增強是直接給予能力", "人有與生俱來對抗困頓和疾病之重生力量", "人在遭遇困難與挫折時，仍然具備能克服逆境與厄運的復原力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05171', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在社會個案工作專業關係的基本原則中，「有目的的情感表達」在界定上不包含下列那項？', '["社會工作者能夠傾聽案主表達的感受", "對案主提供心理支持", "接納案主的敵意與消極性情感", "適度地對案主表達對其意思的了解"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05172', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在一個身心障礙者家長情緒支持團體中，領導者和成員說明：「提醒大家，不能在團體之外，私 下與他人談論團體中其他成員的事。不過即使大家都清楚這樣的狀況，你們在團體內討論的事 情，無法完全保證不會被團體外的其他人知道。若您清楚這樣的情況，還願意參與團體，我們就 可以開始今天的團體。」以上屬於下列那項倫理規範？', '["告知暨徵求同意", "領導者的專業知能與訓練", "團體聚會時適切的行為舉止", "維護團體成員之身心安全"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05173', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「大家剛剛聽了美臻的分享，知道她目前正在為中風的母親，尋找合適的養護中心，不曉得其他 成員有沒有使用過類似的資源？或是知道那個養護中心，適合美臻母親的需要？」上述是在一個 家庭照顧者互助團體中，領導者說的一段話，領導者所運用的技巧為下列何者？', '["示範與角色扮演", "連結成員的溝通", "支持團體成員", "使團體過程明確清楚"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05174', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '幾個機構的社會工作者關心發展遲緩兒童家長罹患憂鬱症個案增多的情形，這些家長多屬於在三 個月內孩子被診斷為發展遲緩者。因此，提議從這些剛被診斷為發展遲緩個案的家長中，邀請他 們參加發展遲緩兒童家庭情緒支持團體。前述團體目的的形成，屬於下列那種方式？', '["由機構員工促成", "由潛在成員促成", "由當地社區促成", "由服務對象促成"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05175', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關「處遇性團體」與「任務性團體」的比較，下列何者錯誤？', '["處遇性團體的成效評估，著重在成員處遇目標的達成情況；任務性團體的成效評估，著重在是 否達成任務、命令或產出結果", "處遇性團體成員之同質性高，即使自我揭露低，也能了解彼此的狀況；任務性團體需要完成任 務，因此成員自我揭露高，才能創造更緊密的互動與理解", "處遇性團體的聚會經常是保密的；任務性團體的聚會，有些是保密的、有些則可以公開", "處遇性團體的聚會程序比較有彈性；任務性團體則比較傾向有正式化的規則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05176', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在處遇性團體中，領導者關心成員若要達到目標，則必須對他們的家庭、工作場域或是所生活的 社區等，能否提供給他們合適的資源進行了解。前述代表著領導者進行那個面向的「預估」 （assessment）？', '["預估團體整體的功能", "預估團體成員的功能", "預估團體的環境", "預估團體介入的成效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05177', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在一個減重團體中，領導者建立「夥伴制度」，當該週減重達成目標時，其他成員要以口頭或寫 卡片的方式，稱讚他的表現。前述做法是「維持和普及化團體改變的成效」中那種處遇技巧？', '["預防在冷漠環境中的挫敗", "運用各種情境和環境的設計", "善用自然發生的結果", "協助成員獨立解決問題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05178', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關「任務性團體」優點與缺點的敘述，下列何者錯誤？', '["不論個人能力為何，團體取向強調集思廣益，在解決問題與做決策上，通常比個別取向有效", "解決團體問題會比個人問題，要花較多的時間", "他人的意見可能會對具有最佳解決問題能力者產生干擾", "參與團體討論與分享做決策之機會，可以將抗拒改變的情況降至最低"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05179', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關社會團體工作的社會目標模型、治療模型與交互模型（互惠模型）三個模型，下列何者正確？', '["社會目標模型工作聚焦在改善因應技巧", "互惠模型聚焦在較大的社會、鄰里和社會環境脈絡中的個人", "社會目標模型的工作者角色是使能者", "治療模型的工作者角色是調解者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
